ALGORITHM SystemCall
INPUT: system_call_number, parameters
OUTPUT: result/status

// Step 1: User Program prepares system call
BEGIN
 // User program loads syscall number and parameters
 LOAD syscall_number INTO register
 LOAD parameters INTO appropriate registers

 // Step 2: Execute trap instruction to switch to kernel mode
 EXECUTE TRAP instruction

 // CPU switches from User Mode to Kernel Mode
 SWITCH_MODE(from_user_mode, to_kernel_mode)

 // Step 3: Save CPU state
 SAVE current_process_state()

 // Step 4: Kernel identifies the system call
 SELECT handler FROM syscall_table USING syscall_number

 // Step 5: Validate parameters
 IF NOT validate_parameters(parameters) THEN
 RETURN error_code
 END IF

 // Step 6: Execute the system call handler
 CALL handler WITH parameters
 STORE result IN return_value_register

 // Step 7: Restore CPU state
 RESTORE current_process_state()

 // Step 8: Return to user mode
 SWITCH_MODE(from_kernel_mode, to_user_mode)

 // Step 9: Resume user program execution
 RETURN result TO user_program
END

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <errno.h>

/*
 * Operating System Operations: Process Management System Calls
 * Demonstrates: fork(), exec(), wait(), getpid(), getppid()
 */

void demonstrate_process_creation() {
 printf("\n=== Process Creation (fork) ===\n");

 pid_t pid = fork();

 if (pid < 0) {
 // Fork failed
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 else if (pid == 0) {
 // Child process
 printf("[CHILD] PID: %d, Parent PID: %d\n", getpid(), getppid());
 printf("[CHILD] Child process executing...\n");

 // Child does some work then exits
 sleep(1);
 printf("[CHILD] Child exiting\n");
 exit(0); // System call: exit
 }
 else {
 // Parent process
 printf("[PARENT] PID: %d, Child PID: %d\n", getpid(), pid);
 printf("[PARENT] Parent waiting for child...\n");

 int status;
 wait(&status); // System call: wait - parent blocks until child terminates

 if (WIFEXITED(status)) {
 printf("[PARENT] Child exited with status: %d\n", WEXITSTATUS(status));
 }
 printf("[PARENT] Parent continuing after child termination\n");
 }
}

void demonstrate_exec() {
 printf("\n=== Process Execution (exec) ===\n");

 pid_t pid = fork();

 if (pid == 0) {
 // Child will replace its image with 'ls' command
 printf("[CHILD] Before exec - PID: %d\n", getpid());

 // exec system call replaces current process image
 char *args[] = {"ls", "-l", "./", NULL};
 execvp("ls", args); // If successful, this never returns

 // Only reached if exec fails
 perror("exec failed");
 exit(EXIT_FAILURE);
 }
 else if (pid > 0) {
 // Parent waits for child
 wait(NULL);
 printf("[PARENT] Child completed exec operation\n");
 }
}

void demonstrate_multiple_processes() {
 printf("\n=== Multiple Process Creation ===\n");

 pid_t pids[3];

 for (int i = 0; i < 3; i++) {
 pids[i] = fork();

 if (pids[i] == 0) {
 // Child process
 printf("[Child %d] PID: %d, working on task %d\n", i+1, getpid(), i+1);
 sleep(1);
 printf("[Child %d] Task %d completed\n", i+1, i+1);
 exit(i + 1);
 }
 else if (pids[i] < 0) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 }

 // Parent waits for all children
 printf("[Parent] Created 3 children, waiting for completion...\n");

 int status;
 for (int i = 0; i < 3; i++) {
 wait(&status);
 printf("[Parent] Child %d finished with status: %d\n", 
 i + 1, WEXITSTATUS(status));
 }
 printf("[Parent] All children completed\n");
}

void demonstrate_info_calls() {
 printf("\n=== Information System Calls ===\n");

 // Get process information
 printf("Process ID (getpid): %d\n", getpid());
 printf("Parent Process ID (getppid): %d\n", getppid());
 printf("User ID (getuid): %d\n", getuid());
 printf("Group ID (getgid): %d\n", getgid());
}

void demonstrate_orphan_process() {
 printf("\n=== Orphan Process Demo ===\n");

 pid_t pid = fork();

 if (pid == 0) {
 // Child process - parent will exit before child
 printf("[Child] Starting, PID: %d, Parent: %d\n", getpid(), getppid());
 sleep(2); // Wait for parent to exit
 printf("[Child] Now Parent is: %d (adopted by init)\n", getppid());
 exit(0);
 }
 else {
 // Parent exits immediately - child becomes orphan
 printf("[Parent] PID: %d exiting immediately\n", getpid());
 exit(0); // Parent exits, child becomes orphan
 }
}

int main() {
 printf("========================================\n");
 printf("OS Operations: Process Management\n");
 printf("========================================\n");

 // Demonstrate basic information calls
 demonstrate_info_calls();

 // Demonstrate process creation
 demonstrate_process_creation();

 // Demonstrate exec system call
 demonstrate_exec();

 // Demonstrate multiple processes
 demonstrate_multiple_processes();

 // Uncomment to see orphan process behavior
 // demonstrate_orphan_process();

 printf("\n=== All demonstrations completed ===\n");
 return 0;
}
